from flask import Flask, request, jsonify
import psycopg2
from psycopg2 import sql
from psycopg2.extras import RealDictCursor
import re
from functools import wraps

app = Flask(__name__)

DB_CONFIG = {
    'host': 'localhost',
    'database': 'analytics_db',
    'user': 'your_username',
    'password': 'your_password',
    'port': 5432
}

ALLOWED_TABLES = ['users', 'orders', 'products', 'transactions', 'analytics']

ALLOWED_OPERATORS = ['=', '!=', '>', '<', '>=', '<=', 'LIKE', 'IN', 'NOT IN', 'IS NULL', 'IS NOT NULL']

def get_db_connection():
    return psycopg2.connect(**DB_CONFIG)

def validate_identifier(identifier):
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', identifier):
        raise ValueError(f"Invalid identifier: {identifier}")
    return identifier

def validate_table_name(table_name):
    validate_identifier(table_name)
    if table_name not in ALLOWED_TABLES:
        raise ValueError(f"Table {table_name} is not allowed")
    return table_name

def error_handler(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        try:
            return f(*args, **kwargs)
        except ValueError as e:
            return jsonify({'error': str(e)}), 400
        except psycopg2.Error as e:
            return jsonify({'error': f'Database error: {str(e)}'}), 500
        except Exception as e:
            return jsonify({'error': f'Internal server error: {str(e)}'}), 500
    return wrapper

def build_where_clause(filters):
    if not filters:
        return sql.SQL(""), []
    
    conditions = []
    params = []
    
    for filter_item in filters:
        column = validate_identifier(filter_item.get('column'))
        operator = filter_item.get('operator', '=').upper()
        value = filter_item.get('value')
        
        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Operator {operator} is not allowed")
        
        if operator in ['IS NULL', 'IS NOT NULL']:
            conditions.append(
                sql.SQL("{} {}").format(
                    sql.Identifier(column),
                    sql.SQL(operator)
                )
            )
        elif operator == 'IN' or operator == 'NOT IN':
            if not isinstance(value, list):
                raise ValueError(f"Value for {operator} must be a list")
            placeholders = sql.SQL(', ').join([sql.Placeholder()] * len(value))
            conditions.append(
                sql.SQL("{} {} ({})").format(
                    sql.Identifier(column),
                    sql.SQL(operator),
                    placeholders
                )
            )
            params.extend(value)
        else:
            conditions.append(
                sql.SQL("{} {} {}").format(
                    sql.Identifier(column),
                    sql.SQL(operator),
                    sql.Placeholder()
                )
            )
            params.append(value)
    
    where_clause = sql.SQL(" WHERE ") + sql.SQL(" AND ").join(conditions)
    return where_clause, params

@app.route('/query', methods=['POST'])
@error_handler
def query_data():
    data = request.get_json()
    
    if not data:
        return jsonify({'error': 'No data provided'}), 400
    
    table_name = validate_table_name(data.get('table'))
    columns = data.get('columns', ['*'])
    filters = data.get('filters', [])
    order_by = data.get('order_by')
    limit = data.get('limit')
    offset = data.get('offset')
    
    if columns != ['*']:
        columns = [validate_identifier(col) for col in columns]
        select_clause = sql.SQL(', ').join([sql.Identifier(col) for col in columns])
    else:
        select_clause = sql.SQL('*')
    
    query = sql.SQL("SELECT {} FROM {}").format(
        select_clause,
        sql.Identifier(table_name)
    )
    
    where_clause, params = build_where_clause(filters)
    query = query + where_clause
    
    if order_by:
        order_column = validate_identifier(order_by.get('column'))
        order_direction = order_by.get('direction', 'ASC').upper()
        if order_direction not in ['ASC', 'DESC']:
            raise ValueError("Order direction must be ASC or DESC")
        query = query + sql.SQL(" ORDER BY {} {}").format(
            sql.Identifier(order_column),
            sql.SQL(order_direction)
        )
    
    if limit:
        if not isinstance(limit, int) or limit <= 0:
            raise ValueError("Limit must be a positive integer")
        query = query + sql.SQL(" LIMIT {}").format(sql.Literal(limit))
    
    if offset:
        if not isinstance(offset, int) or offset < 0:
            raise ValueError("Offset must be a non-negative integer")
        query = query + sql.SQL(" OFFSET {}").format(sql.Literal(offset))
    
    conn = get_db_connection()
    try:
        with conn.cursor(cursor_factory=RealDictCursor) as cursor:
            cursor.execute(query, params)
            results = cursor.fetchall()
            return jsonify({
                'success': True,
                'data': results,
                'count': len(results)
            })
    finally:
        conn.close()

